local Players=game:GetService("Players") local RunService=game:GetService("RunService") local UserInputService=game:GetService("UserInputService") local TweenService=game:GetService("TweenService") local Lighting=game:GetService("Lighting") local Workspace=game:GetService("Workspace") local Camera=Workspace.CurrentCamera local player=Players.LocalPlayer local character=player.Character or player.CharacterAdded:Wait() local humanoid=character:WaitForChild("Humanoid") local rootPart=character:WaitForChild("HumanoidRootPart") local consoleVisible=false local consoleFrame,consoleTextBox,outputFrame,titleFrame,background local toggles={} local flyConnection,noclipConnection,floatConnection,swimConnection,aimbotConnection,espConnection local floatPart local messages={ god_on="God mode: ON", god_off="God mode: OFF", fling_on="Fling: ON", fling_off="Fling: OFF", fly_on="Fly: ON (Speed: %s)", fly_off="Fly: OFF", noclip_on="Noclip: ON", noclip_off="Noclip: OFF", fb_on="Fullbright: ON", fb_off="Fullbright: OFF", lowgraphics_on="Low Graphics: ON", lowgraphics_off="Low Graphics: OFF", infjump_on="Infinite Jump: ON", infjump_off="Infinite Jump: OFF", esp_on="ESP: ON", esp_off="ESP: OFF", aimbot_on="Aimbot: ON", aimbot_off="Aimbot: OFF", guiscale_on="GUI Scale: ON (Adjust with +/-)", guiscale_off="GUI Scale: OFF", float_on="Float Platform: ON", float_off="Float Platform: OFF", swim_on="Swim: ON", swim_off="Swim: OFF", goto_on="Goto: ON (Target: %s)", goto_off="Goto: OFF", nolimitzoom_on="No Limit Zoom: ON", nolimitzoom_off="No Limit Zoom: OFF", killall_on="Kill All: ON (Visual)", killall_off="Kill All: OFF", speed_on="Speed: ON (%s)", speed_off="Speed: OFF", player_not_found="Player '%s' not found", usage_goto="Usage: goto [player name] on/off", usage_speed="Usage: speed on/off [speed]", usage_fly="Usage: fly on/off [speed]", title_on="Title: ON", title_off="Title: OFF", console_opened="Console opened", console_closed="Console closed", } local function addOutput(text,color) if not outputFrame then return end local label=Instance.new("TextLabel") label.Size=UDim2.new(1,-20,0,22) label.Position=UDim2.new(0,10,0,#outputFrame:GetChildren()*22) label.BackgroundTransparency=1 label.Text=text label.TextColor3=color or Color3.new(0.4,1,0.4) label.TextXAlignment=Enum.TextXAlignment.Left label.Font=Enum.Font.SourceSans label.TextSize=17 label.Parent=outputFrame outputFrame.CanvasSize=UDim2.new(0,0,0,#outputFrame:GetChildren()*22) outputFrame.CanvasPosition=Vector2.new(0,outputFrame.CanvasSize.Y.Offset) end local function setGodMode(state) toggles.god=state if state then if character and humanoid then humanoid.MaxHealth=math.huge humanoid.Health=math.huge end addOutput(messages.god_on,Color3.new(0.4,1,0.4)) else if character and humanoid then humanoid.MaxHealth=100 end addOutput(messages.god_off,Color3.new(1,0.4,0.4)) end end local function setFling(state) toggles.fling=state if state then if rootPart then local bodyAngularVelocity=Instance.new("BodyAngularVelocity") bodyAngularVelocity.AngularVelocity=Vector3.new(9999,9999,9999) bodyAngularVelocity.MaxTorque=Vector3.new(999999,999999,999999) bodyAngularVelocity.Parent=rootPart toggles.flingObject=bodyAngularVelocity end addOutput(messages.fling_on,Color3.new(0.4,1,0.4)) else if toggles.flingObject then toggles.flingObject:Destroy() toggles.flingObject=nil end addOutput(messages.fling_off,Color3.new(1,0.4,0.4)) end end local function setFly(state,speed) local flySpeed=speed and tonumber(speed) or 50 toggles.fly=state toggles.flySpeed=flySpeed if flyConnection then flyConnection:Disconnect() end if state then local bodyVelocity=Instance.new("BodyVelocity") bodyVelocity.Velocity=Vector3.new(0,0,0) bodyVelocity.MaxForce=Vector3.new(4000,4000,4000) bodyVelocity.Parent=rootPart flyConnection=RunService.RenderStepped:Connect(function() if not toggles.fly then return end local moveDirection=Vector3.new() if UserInputService:IsKeyDown(Enum.KeyCode.W) then moveDirection=moveDirection+Camera.CFrame.LookVector*flySpeed end if UserInputService:IsKeyDown(Enum.KeyCode.S) then moveDirection=moveDirection-Camera.CFrame.LookVector*flySpeed end if UserInputService:IsKeyDown(Enum.KeyCode.A) then moveDirection=moveDirection-Camera.CFrame.RightVector*flySpeed end if UserInputService:IsKeyDown(Enum.KeyCode.D) then moveDirection=moveDirection+Camera.CFrame.RightVector*flySpeed end if UserInputService:IsKeyDown(Enum.KeyCode.Space) then moveDirection=moveDirection+Vector3.new(0,flySpeed,0) end if UserInputService:IsKeyDown(Enum.KeyCode.LeftControl) then moveDirection=moveDirection-Vector3.new(0,flySpeed,0) end if rootPart and bodyVelocity and bodyVelocity.Parent then bodyVelocity.Velocity=moveDirection end end) addOutput(string.format(messages.fly_on,flySpeed),Color3.new(0.4,1,0.4)) else if rootPart and rootPart:FindFirstChildOfClass("BodyVelocity") then rootPart:FindFirstChildOfClass("BodyVelocity"):Destroy() end if flyConnection then flyConnection:Disconnect() end addOutput(messages.fly_off,Color3.new(1,0.4,0.4)) end end local function setNoclip(state) toggles.noclip=state if noclipConnection then noclipConnection:Disconnect() end if state then noclipConnection=RunService.Stepped:Connect(function() if not toggles.noclip then return end if character then for _,part in pairs(character:GetDescendants()) do if part:IsA("BasePart") then part.CanCollide=false end end end end) addOutput(messages.noclip_on,Color3.new(0.4,1,0.4)) else if character then for _,part in pairs(character:GetDescendants()) do if part:IsA("BasePart") then part.CanCollide=true end end end addOutput(messages.noclip_off,Color3.new(1,0.4,0.4)) end end local function setFullbright(state) toggles.fb=state if state then Lighting.Ambient=Color3.new(1,1,1) Lighting.Brightness=2 Lighting.ColorShift_Top=Color3.new(1,1,1) Lighting.ColorShift_Bottom=Color3.new(1,1,1) Lighting.OutdoorAmbient=Color3.new(1,1,1) addOutput(messages.fb_on,Color3.new(0.4,1,0.4)) else Lighting.Ambient=Color3.new(0,0,0) Lighting.Brightness=1 Lighting.ColorShift_Top=Color3.new(0,0,0) Lighting.ColorShift_Bottom=Color3.new(0,0,0) Lighting.OutdoorAmbient=Color3.new(0,0,0) addOutput(messages.fb_off,Color3.new(1,0.4,0.4)) end end local function setLowGraphics(state) toggles.lowgraphics=state if state then settings().Rendering.QualityLevel=1 Lighting.GlobalShadows=false Lighting.FogEnd=100 addOutput(messages.lowgraphics_on,Color3.new(0.4,1,0.4)) else settings().Rendering.QualityLevel=21 Lighting.GlobalShadows=true Lighting.FogEnd=100000 addOutput(messages.lowgraphics_off,Color3.new(1,0.4,0.4)) end end local function setInfJump(state) toggles.infjump=state if state then local connection connection=UserInputService.JumpRequest:Connect(function() if not toggles.infjump then connection:Disconnect() return end if humanoid then humanoid:ChangeState(Enum.HumanoidStateType.Jumping) end end) toggles.infjumpConnection=connection addOutput(messages.infjump_on,Color3.new(0.4,1,0.4)) else if toggles.infjumpConnection then toggles.infjumpConnection:Disconnect() toggles.infjumpConnection=nil end addOutput(messages.infjump_off,Color3.new(1,0.4,0.4)) end end local function setESP(state) toggles.esp=state if espConnection then espConnection:Disconnect() end if state then espConnection=RunService.RenderStepped:Connect(function() for _,plr in pairs(Players:GetPlayers()) do if plr~=player and plr.Character and plr.Character:FindFirstChild("HumanoidRootPart") then local highlight=plr.Character:FindFirstChildOfClass("Highlight") if not highlight then highlight=Instance.new("Highlight") highlight.FillTransparency=1 highlight.OutlineColor=Color3.new(1,0,0) highlight.OutlineTransparency=0 highlight.DepthMode=Enum.HighlightDepthMode.AlwaysOnTop highlight.Parent=plr.Character end end end end) addOutput(messages.esp_on,Color3.new(0.4,1,0.4)) else for _,plr in pairs(Players:GetPlayers()) do if plr.Character then local highlight=plr.Character:FindFirstChildOfClass("Highlight") if highlight then highlight:Destroy() end end end addOutput(messages.esp_off,Color3.new(1,0.4,0.4)) end end local function setAimbot(state) toggles.aimbot=state if aimbotConnection then aimbotConnection:Disconnect() end if state then aimbotConnection=RunService.RenderStepped:Connect(function() if not toggles.aimbot then return end local closestPlayer,closestDistance=nil,math.huge for _,plr in pairs(Players:GetPlayers()) do if plr~=player and plr.Character and plr.Character:FindFirstChild("Head") then local headPos=plr.Character.Head.Position local screenPos,onScreen=Camera:WorldToScreenPoint(headPos) if onScreen then local distance=(Vector2.new(screenPos.X,screenPos.Y)-Vector2.new(Camera.ViewportSize.X/2,Camera.ViewportSize.Y/2)).Magnitude if distance<closestDistance then closestDistance=distance closestPlayer=plr end end end end if closestPlayer and closestPlayer.Character and closestPlayer.Character:FindFirstChild("Head") then Camera.CFrame=CFrame.new(Camera.CFrame.Position,closestPlayer.Character.Head.Position) end end) addOutput(messages.aimbot_on,Color3.new(0.4,1,0.4)) else addOutput(messages.aimbot_off,Color3.new(1,0.4,0.4)) end end local function setGUIScale(state) toggles.guiscale=state if state then addOutput(messages.guiscale_on,Color3.new(0.4,1,0.4)) else if consoleFrame then consoleFrame.Size=UDim2.new(0.75,0,0.75,0) end addOutput(messages.guiscale_off,Color3.new(1,0.4,0.4)) end end local function setFloat(state) toggles.float=state if floatConnection then floatConnection:Disconnect() end if state then if floatPart and floatPart.Parent then floatPart:Destroy() end floatPart=Instance.new("Part") floatPart.Size=Vector3.new(10,1,10) floatPart.Position=rootPart.Position-Vector3.new(0,3,0) floatPart.Anchored=true floatPart.CanCollide=true floatPart.Transparency=1 floatPart.Parent=Workspace floatConnection=RunService.RenderStepped:Connect(function() if not toggles.float then return end if floatPart and floatPart.Parent then floatPart.Position=rootPart.Position-Vector3.new(0,3,0) end end) addOutput(messages.float_on,Color3.new(0.4,1,0.4)) else if floatPart then floatPart:Destroy() floatPart=nil end addOutput(messages.float_off,Color3.new(1,0.4,0.4)) end end local function setUnfloat(state) if state then if floatPart then floatPart:Destroy() floatPart=nil end toggles.float=false if floatConnection then floatConnection:Disconnect() end addOutput(messages.float_off,Color3.new(1,0.4,0.4)) end end local function setSwim(state) toggles.swim=state if swimConnection then swimConnection:Disconnect() end if state then swimConnection=RunService.RenderStepped:Connect(function() if not toggles.swim then return end if humanoid then humanoid:ChangeState(Enum.HumanoidStateType.Swimming) end end) addOutput(messages.swim_on,Color3.new(0.4,1,0.4)) else addOutput(messages.swim_off,Color3.new(1,0.4,0.4)) end end local function setGoto(state,targetName) if not state then toggles.goto=false toggles.gotoTarget=nil addOutput(messages.goto_off,Color3.new(1,0.4,0.4)) return end local targetPlayer=Players:FindFirstChild(targetName) if targetPlayer and targetPlayer.Character and targetPlayer.Character:FindFirstChild("HumanoidRootPart") then if rootPart then rootPart.CFrame=targetPlayer.Character.HumanoidRootPart.CFrame*CFrame.new(0,5,5) end toggles.goto=true toggles.gotoTarget=targetPlayer addOutput(string.format(messages.goto_on,targetName),Color3.new(0.4,1,0.4)) else addOutput(string.format(messages.player_not_found,targetName),Color3.new(1,0.8,0.2)) end end local function setNoLimitZoom(state) toggles.nolimitzoom=state if state then local camera=Workspace.CurrentCamera camera:GetPropertyChangedSignal("FieldOfView"):Connect(function() if toggles.nolimitzoom then if camera.FieldOfView<1 then camera.FieldOfView=1 end end end) addOutput(messages.nolimitzoom_on,Color3.new(0.4,1,0.4)) else Workspace.CurrentCamera.FieldOfView=70 addOutput(messages.nolimitzoom_off,Color3.new(1,0.4,0.4)) end end local function setKillAll(state) toggles.killall=state if state then for _,plr in pairs(Players:GetPlayers()) do if plr~=player and plr.Character and plr.Character:FindFirstChild("Humanoid") then local hum=plr.Character.Humanoid hum.Health=0 local part=Instance.new("Part") part.Shape=Enum.PartType.Ball part.BrickColor=BrickColor.new("Really red") part.Size=Vector3.new(5,5,5) part.CFrame=plr.Character.HumanoidRootPart.CFrame part.Anchored=true part.CanCollide=false part.Parent=Workspace game:GetService("Debris"):AddItem(part,2) end end addOutput(messages.killall_on,Color3.new(0.4,1,0.4)) else addOutput(messages.killall_off,Color3.new(1,0.4,0.4)) end end local function setSpeed(state,speedValue) local speed=speedValue and tonumber(speedValue) or 50 toggles.speed=state toggles.speedValue=speed if state then if humanoid then humanoid.WalkSpeed=speed end addOutput(string.format(messages.speed_on,speed),Color3.new(0.4,1,0.4)) else if humanoid then humanoid.WalkSpeed=16 end addOutput(messages.speed_off,Color3.new(1,0.4,0.4)) end end local function setTitle(state) toggles.title=state if titleFrame then titleFrame.Visible=state end addOutput(state and messages.title_on or messages.title_off,state and Color3.new(0.4,1,0.4) or Color3.new(1,0.4,0.4)) end local function showCommands() addOutput("═══════════════════════════════════════",Color3.new(1,0.5,0)) addOutput("            AVAILABLE COMMANDS",Color3.new(1,0.5,0)) addOutput("═══════════════════════════════════════",Color3.new(1,0.5,0)) addOutput("god on/off          - God mode",Color3.new(1,1,1)) addOutput("fling on/off        - Fling model",Color3.new(1,1,1)) addOutput("fly on/off [speed]  - Fly",Color3.new(1,1,1)) addOutput("noclip on/off       - No clip",Color3.new(1,1,1)) addOutput("fb on/off           - Fullbright",Color3.new(1,1,1)) addOutput("lowgraphics on/off  - Low graphics",Color3.new(1,1,1)) addOutput("infjump on/off      - Infinite jump",Color3.new(1,1,1)) addOutput("esp on/off          - Player outline",Color3.new(1,1,1)) addOutput("aimbot on/off       - Aimbot",Color3.new(1,1,1)) addOutput("guiscale on/off     - GUI scale",Color3.new(1,1,1)) addOutput("float on/off        - Invisible platform",Color3.new(1,1,1)) addOutput("unfloat on/off      - Remove platform",Color3.new(1,1,1)) addOutput("swim on/off         - Air swimming",Color3.new(1,1,1)) addOutput("goto [p] on/off     - Teleport to player",Color3.new(1,1,1)) addOutput("nolimitzoom on/off  - No zoom limit",Color3.new(1,1,1)) addOutput("killall on/off      - Kill all (visual)",Color3.new(1,1,1)) addOutput("speed on/off [sp]   - Player speed",Color3.new(1,1,1)) addOutput("tittle on/off       - Toggle title",Color3.new(1,1,1)) addOutput("commands            - Show this list",Color3.new(1,1,1)) addOutput("═══════════════════════════════════════",Color3.new(1,0.5,0)) end local function processCommand(input) local parts={} for part in input:gmatch("%S+") do table.insert(parts,part:lower()) end if #parts==0 then return end local command=parts[1] local subCommand=parts[2] local param=parts[3] if command=="god" then if subCommand=="on" then setGodMode(true) elseif subCommand=="off" then setGodMode(false) end elseif command=="fling" then if subCommand=="on" then setFling(true) elseif subCommand=="off" then setFling(false) end elseif command=="fly" then if subCommand=="on" then setFly(true,param) elseif subCommand=="off" then setFly(false) else setFly(true,subCommand) end elseif command=="noclip" then if subCommand=="on" then setNoclip(true) elseif subCommand=="off" then setNoclip(false) end elseif command=="fb" then if subCommand=="on" then setFullbright(true) elseif subCommand=="off" then setFullbright(false) end elseif command=="lowgraphics" then if subCommand=="on" then setLowGraphics(true) elseif subCommand=="off" then setLowGraphics(false) end elseif command=="infjump" then if subCommand=="on" then setInfJump(true) elseif subCommand=="off" then setInfJump(false) end elseif command=="esp" then if subCommand=="on" then setESP(true) elseif subCommand=="off" then setESP(false) end elseif command=="aimbot" then if subCommand=="on" then setAimbot(true) elseif subCommand=="off" then setAimbot(false) end elseif command=="guiscale" then if subCommand=="on" then setGUIScale(true) elseif subCommand=="off" then setGUIScale(false) end elseif command=="float" then if subCommand=="on" then setFloat(true) elseif subCommand=="off" then setFloat(false) end elseif command=="unfloat" then if subCommand=="on" then setUnfloat(true) elseif subCommand=="off" then setUnfloat(false) end elseif command=="swim" then if subCommand=="on" then setSwim(true) elseif subCommand=="off" then setSwim(false) end elseif command=="goto" then if subCommand and parts[3] and parts[3]=="on" then setGoto(true,subCommand) elseif subCommand and parts[3] and parts[3]=="off" then setGoto(false) else addOutput(messages.usage_goto,Color3.new(1,1,0)) end elseif command=="nolimitzoom" then if subCommand=="on" then setNoLimitZoom(true) elseif subCommand=="off" then setNoLimitZoom(false) end elseif command=="killall" then if subCommand=="on" then setKillAll(true) elseif subCommand=="off" then setKillAll(false) end elseif command=="speed" then if subCommand=="on" then setSpeed(true,param) elseif subCommand=="off" then setSpeed(false) else setSpeed(true,subCommand) end elseif command=="tittle" then if subCommand=="on" then setTitle(true) elseif subCommand=="off" then setTitle(false) end elseif command=="commands" then showCommands() else addOutput("Unknown command: "..command,Color3.new(1,0.4,0.4)) end end local function createConsole() local screenGui=Instance.new("ScreenGui") screenGui.Name="InfinityHackGUI" screenGui.ResetOnSpawn=false screenGui.ZIndexBehavior=Enum.ZIndexBehavior.Sibling screenGui.Parent=player:WaitForChild("PlayerGui") background=Instance.new("Frame") background.Name="Background" background.Size=UDim2.new(1,0,1,0) background.BackgroundColor3=Color3.new(0,0,0) background.BackgroundTransparency=0.75 background.BorderSizePixel=0 background.Visible=false background.ZIndex=999 background.Parent=screenGui consoleFrame=Instance.new("Frame") consoleFrame.Name=