le then if input.KeyCode==Enum.KeyCode.Equals then consoleFrame.Size=consoleFrame.Size*1.1 elseif input.KeyCode==Enum.KeyCode.Minus then consoleFrame.Size=consoleFrame.Size*0.9 end end end) end createConsole() UserInputService.InputBegan:Connect(function(input,gameProcessed) if gameProcessed then return end if input.KeyCode==Enum.KeyCode.F2 then consoleVisible=not consoleVisible consoleFrame.Visible=consoleVisible if background then background.Visible=consoleVisible end if consoleVisible then consoleTextBox:CaptureFocus() addOutput(messages.console_opened,Color3.new(0.4,1,0.4)) else addOutput(messages.console_closed,Color3.new(1,0.4,0.4)) end end end) player.CharacterAdded:Connect(function(newCharacter) character=newCharacter humanoid=character:WaitForChild("Humanoid") rootPart=character:WaitForChild("HumanoidRootPart") if toggles.god then setGodMode(true) end if toggles.fling then setFling(true) end if toggles.fly then setFly(true,toggles.flySpeed) end if toggles.noclip then setNoclip(true) end if toggles.float then setFloat(true) end if toggles.swim then setSwim(true) end if toggles.speed then setSpeed(true,toggles.speedValue) end end) addOutput("INFINITY HACK v0.1.0",Color3.new(1,0.5,0)) addOutput("Press F2 to open console | Type 'commands' for help",Color3.new(0.7,0.7,0.7))
